using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

public sealed partial class WebSearchTool : IDisposable
{
    private readonly HttpClient _http;

    public WebSearchTool()
    {
        _http = new HttpClient { Timeout = TimeSpan.FromSeconds(15) };
        _http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    }

    [Description("Search the web for information. Returns relevant results with titles and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            using var response = await _http.GetAsync(url);
            response.EnsureSuccessStatusCode();

            var ddg = await response.Content.ReadFromJsonAsync<DdgResponse>();
            if (ddg is null)
                return "No results found. Try refining your search query.";

            var results = new List<string>();

            if (!string.IsNullOrWhiteSpace(ddg.Abstract))
                results.Add($"Summary: {ddg.Abstract}\nSource: {ddg.AbstractURL}");

            if (!string.IsNullOrWhiteSpace(ddg.Answer))
                results.Add($"Answer: {ddg.Answer}");

            foreach (var topic in ddg.RelatedTopics?.Take(8) ?? [])
            {
                if (!string.IsNullOrWhiteSpace(topic.Text))
                    results.Add($"- {topic.Text}\n  URL: {topic.FirstURL}");
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found for this query. Try different search terms.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Fetch and extract the text content from a web page URL. Use this to read detailed information from a specific page found via search.")]
    public async Task<string> FetchWebPageAsync(
        [Description("The full URL of the web page to fetch")] string url)
    {
        try
        {
            var html = await _http.GetStringAsync(url);

            // Strip script and style blocks
            var text = ScriptStyleRegex().Replace(html, "");
            // Strip HTML tags
            text = HtmlTagRegex().Replace(text, " ");
            // Decode HTML entities
            text = System.Net.WebUtility.HtmlDecode(text);
            // Normalize whitespace
            text = WhitespaceRegex().Replace(text, " ").Trim();

            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n... [content truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract text content from this page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    public void Dispose() => _http.Dispose();

    [GeneratedRegex(@"<(script|style)[^>]*>[\s\S]*?</\1>", RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();

    private sealed class DdgResponse
    {
        [JsonPropertyName("Abstract")]
        public string? Abstract { get; set; }

        [JsonPropertyName("AbstractURL")]
        public string? AbstractURL { get; set; }

        [JsonPropertyName("Answer")]
        public string? Answer { get; set; }

        [JsonPropertyName("RelatedTopics")]
        public List<DdgTopic>? RelatedTopics { get; set; }
    }

    private sealed class DdgTopic
    {
        [JsonPropertyName("Text")]
        public string? Text { get; set; }

        [JsonPropertyName("FirstURL")]
        public string? FirstURL { get; set; }
    }
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

public sealed class NoteTool
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note. Use this to record each important finding during research.")]
    public string SaveNote(
        [Description("A brief title describing the finding")] string title,
        [Description("The detailed content of the finding")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Call this to review findings before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var formatted = _notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n{n.Content}");

        return $"Total notes: {_notes.Count}\n\n{string.Join("\n\n", formatted)}";
    }
}

