+public sealed partial class WebSearchTool : IDisposable
+{
+    private readonly HttpClient _http;
+
+    public WebSearchTool()
+    {
+        _http = new HttpClient { Timeout = TimeSpan.FromSeconds(15) };
+        _http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
+    }
+
+    [Description("Search the web for information. Returns relevant results with titles and snippets.")]
+    public async Task<string> SearchWebAsync(
+        [Description("The search query string")] string query)
+    {
+        try
+        {
+            var encoded = Uri.EscapeDataString(query);
+            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
+
+            using var response = await _http.GetAsync(url);
+            response.EnsureSuccessStatusCode();
+
+            var ddg = await response.Content.ReadFromJsonAsync<DdgResponse>();
+            if (ddg is null)
+                return "No results found. Try refining your search query.";
+
+            var results = new List<string>();
+
+            if (!string.IsNullOrWhiteSpace(ddg.Abstract))
+                results.Add($"Summary: {ddg.Abstract}\nSource: {ddg.AbstractURL}");
+
+            if (!string.IsNullOrWhiteSpace(ddg.Answer))
+                results.Add($"Answer: {ddg.Answer}");
+
+            foreach (var topic in ddg.RelatedTopics?.Take(8) ?? [])
+            {
+                if (!string.IsNullOrWhiteSpace(topic.Text))
+                    results.Add($"- {topic.Text}\n  URL: {topic.FirstURL}");
+            }
+
+            return results.Count > 0
+                ? string.Join("\n\n", results)
+                : "No results found for this query. Try different search terms.";
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed: {ex.Message}. Try a different query.";
+        }
+    }
+
+    [Description("Fetch and extract the text content from a web page URL. Use this to read detailed information from a specific page found via search.")]
+    public async Task<string> FetchWebPageAsync(
+        [Description("The full URL of the web page to fetch")] string url)
+    {
+        try
+        {
+            var html = await _http.GetStringAsync(url);
+
+            // Strip script and style blocks
+            var text = ScriptStyleRegex().Replace(html, "");
+            // Strip HTML tags
+            text = HtmlTagRegex().Replace(text, " ");
+            // Decode HTML entities
+            text = System.Net.WebUtility.HtmlDecode(text);
+            // Normalize whitespace
+            text = WhitespaceRegex().Replace(text, " ").Trim();
+
+            const int maxLength = 4000;
+            if (text.Length > maxLength)
+                text = text[..maxLength] + "\n... [content truncated]";
+
+            return string.IsNullOrWhiteSpace(text)
