using System.Reflection;

var asmNames = new[] {
    "/home/runner/.nuget/packages/microsoft.agents.ai/1.6.0/lib/net10.0/Microsoft.Agents.AI.dll",
    "/home/runner/.nuget/packages/microsoft.agents.ai.abstractions/1.6.0/lib/net10.0/Microsoft.Agents.AI.Abstractions.dll"
};

foreach (var path in asmNames)
{
    var asm = Assembly.LoadFrom(path);
    Console.WriteLine($"=== {Path.GetFileName(path)} ===");
