cat > /tmp/inspect-agent/Program.cs << 'CSEOF'
using System.Reflection;

// Load all assemblies in the directory
var dir = Path.GetDirectoryName(typeof(object).Assembly.Location)!;
foreach (var dll in Directory.GetFiles(AppContext.BaseDirectory, "Microsoft.Agents.*.dll"))
{
    try { Assembly.LoadFrom(dll); } catch { }
}

foreach (var asm in AppDomain.CurrentDomain.GetAssemblies().Where(a => a.FullName?.Contains("Agents") == true).OrderBy(a => a.FullName))
{
    Console.WriteLine($"\n=== {asm.GetName().Name} ===");
    try
    {
        foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
        {
            var bases = new List<string>();
            if (t.BaseType != null && t.BaseType != typeof(object)) bases.Add(t.BaseType.Name);
            bases.AddRange(t.GetInterfaces().Select(i => i.Name));
            var baseStr = bases.Count > 0 ? " : " + string.Join(", ", bases) : "";
            Console.WriteLine($"\n  TYPE: {t.FullName}{baseStr}");
            foreach (var c in t.GetConstructors())
                Console.WriteLine($"    CTOR({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
            foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
                Console.WriteLine($"    PROP: {p.Name} : {p.PropertyType.Name}");
            foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
                Console.WriteLine($"    METHOD: {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"  ERROR: {ex.Message}");
    }
}
